-- Audit Triggers Migration for billing module
-- Generated by backbone-schema
--
-- This migration adds automatic timestamp management triggers
-- to all tables with audit metadata fields.
--
-- Triggers automatically set:
--   - metadata->'created_at' on INSERT
--   - metadata->'updated_at' on INSERT and UPDATE

-- ==============================================================================
-- Table: AgentEarning (agent_earnings)
-- ==============================================================================

-- Function to set metadata timestamps
CREATE OR REPLACE FUNCTION agent_earnings_audit_timestamp() RETURNS trigger AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        NEW.metadata = jsonb_set(NEW.metadata::jsonb, '{created_at}', to_jsonb(NOW()));
        NEW.metadata = jsonb_set(NEW.metadata::jsonb, '{updated_at}', to_jsonb(NOW()));
    ELSIF TG_OP = 'UPDATE' THEN
        NEW.metadata = jsonb_set(NEW.metadata::jsonb, '{updated_at}', to_jsonb(NOW()));
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Trigger to set timestamps on INSERT
DROP TRIGGER IF EXISTS agent_earnings_insert_audit ON agent_earnings;
CREATE TRIGGER agent_earnings_insert_audit BEFORE INSERT ON agent_earnings
    FOR EACH ROW EXECUTE FUNCTION agent_earnings_audit_timestamp();

-- Trigger to set updated_at on UPDATE
DROP TRIGGER IF EXISTS agent_earnings_update_audit ON agent_earnings;
CREATE TRIGGER agent_earnings_update_audit BEFORE UPDATE ON agent_earnings
    FOR EACH ROW EXECUTE FUNCTION agent_earnings_audit_timestamp();

